// Extract results from search callback envelope
// Accepts: { run_id, results: [...], status }
const b = $('Webhook Trigger').first().json.body ?? $('Webhook Trigger').first().json;
const results = b.results || [];
const run_id = b.run_id || 'unknown';

const edges = [];

for (const r of results) {
  // person -> organization edges
  if (r.contact_name && r.organization) {
    edges.push({
      source_type: 'person',
      source_id: run_id,
      target_type: 'organization',
      target_id: run_id,
      edge_reason: (r.contact_name + ' works at ' + r.organization + ' (via search)').slice(0, 500)
    });
  }

  // grant edges
  if (r.raw_data && r.raw_data.grant_name && r.organization) {
    edges.push({
      source_type: 'organization',
      source_id: run_id,
      target_type: 'grant',
      target_id: run_id,
      edge_reason: (r.organization + ' linked to grant: ' + r.raw_data.grant_name).slice(0, 500)
    });
  }

  // event edges
  if (r.raw_data && r.raw_data.event_name && r.organization) {
    edges.push({
      source_type: 'event',
      source_id: run_id,
      target_type: 'organization',
      target_id: run_id,
      edge_reason: (r.organization + ' connected to event: ' + r.raw_data.event_name).slice(0, 500)
    });
  }
}

// Deduplicate by edge_reason
const seen = new Set();
const uniqueEdges = edges.filter(e => {
  const key = e.source_type + ':' + e.target_type + ':' + e.edge_reason;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return [{ json: { edges: uniqueEdges, edge_count: uniqueEdges.length, run_id } }];

const edgeCount = $('Emit Relationship Edges').first().json.edge_count || 0;
const postResult = $json;
return [{ json: {
  ok: true,
  edges_emitted: edgeCount,
  supabase_response: postResult,
  completed_at: new Date().toISOString()
} }];
